12: type Validation struct {
13: 	authorizer plugins.PluginLoaderAuthorizer
14: 	log        log.Logger
15: }
16: 
17: func ProvideValidatorService(authorizer plugins.PluginLoaderAuthorizer) *Validation {
18: 	return NewValidator(authorizer)
19: }
