23: type Loader struct {
24: 	cfg          *pluginsCfg.PluginManagementCfg
25: 	discovery    discovery.Discoverer
26: 	bootstrap    bootstrap.Bootstrapper
27: 	initializer  initialization.Initializer
28: 	termination  termination.Terminator
29: 	validation   validation.Validator
30: 	errorTracker pluginerrs.ErrorTracker
31: 	log          log.Logger
