33: 
34: func New(
35: 	cfg *pluginsCfg.PluginManagementCfg,
36: 	discovery discovery.Discoverer, bootstrap bootstrap.Bootstrapper, validation validation.Validator,
37: 	initializer initialization.Initializer, termination termination.Terminator, errorTracker pluginerrs.ErrorTracker,
38: ) *Loader {
39: 	return &Loader{
40: 		cfg:          cfg,
41: 		discovery:    discovery,
42: 		bootstrap:    bootstrap,
43: 		validation:   validation,
44: 		initializer:  initializer,
45: 		termination:  termination,
46: 		errorTracker: errorTracker,
47: 		log:          log.New("plugin.loader"),
48: 	}
49: }
