51: func (l *Loader) recordError(ctx context.Context, p *plugins.Plugin, err error) {
52: 	var pErr *plugins.Error
53: 	if errors.As(err, &pErr) {
54: 		l.errorTracker.Record(ctx, pErr)
55: 		return
56: 	}
57: 	l.errorTracker.Record(ctx, &plugins.Error{
58: 		PluginID:  p.ID,
59: 		ErrorCode: plugins.ErrorCode(err.Error()),
60: 	})
61: }
62: 
63: func (l *Loader) Load(ctx context.Context, src plugins.PluginSource) ([]*plugins.Plugin, error) {
64: 	end := l.instrumentLoad(ctx, src)
65: 
66: 	st := time.Now()
67: 	discoveredPlugins, err := l.discovery.Discover(ctx, src)
68: 	if err != nil {
69: 		return nil, err
70: 	}
71: 	l.log.Debug("Discovered", "class", src.PluginClass(ctx), "duration", time.Since(st))
72: 
73: 	st = time.Now()
74: 	bootstrappedPlugins := []*plugins.Plugin{}
75: 	for _, foundBundle := range discoveredPlugins {
76: 		bootstrappedPlugin, err := l.bootstrap.Bootstrap(ctx, src, foundBundle)
77: 		if err != nil {
78: 			l.errorTracker.Record(ctx, &plugins.Error{
79: 				PluginID:  foundBundle.Primary.JSONData.ID,
80: 				ErrorCode: plugins.ErrorCode(err.Error()),
81: 			})
82: 			continue
83: 		}
84: 		bootstrappedPlugins = append(bootstrappedPlugins, bootstrappedPlugin...)
85: 	}
86: 	l.log.Debug("Bootstrapped", "class", src.PluginClass(ctx), "duration", time.Since(st))
87: 
88: 	st = time.Now()
89: 	validatedPlugins := []*plugins.Plugin{}
90: 	type validateResult struct {
91: 		bootstrappedPlugin *plugins.Plugin
92: 		err                error
93: 	}
94: 	validateResults := make(chan validateResult, len(bootstrappedPlugins))
95: 
96: 	var limitSize int
97: 	if src.PluginClass(ctx) == plugins.ClassCDN {
98: 		limitSize = min(len(bootstrappedPlugins), concurrencyLimit)
99: 	} else {
100: 		limitSize = 1
101: 	}
102: 	limit := make(chan struct{}, limitSize)
103: 	for _, bootstrappedPlugin := range bootstrappedPlugins {
104: 		limit <- struct{}{}
105: 		go func(p *plugins.Plugin) {
106: 			err := l.validation.Validate(ctx, p)
107: 			validateResults <- validateResult{
108: 				bootstrappedPlugin: bootstrappedPlugin,
109: 				err:                err,
110: 			}
111: 			<-limit
112: 		}(bootstrappedPlugin)
113: 	}
114: 	for i := 0; i < len(bootstrappedPlugins); i++ {
115: 		r := <-validateResults
116: 		if r.err != nil {
117: 			l.recordError(ctx, r.bootstrappedPlugin, r.err)
118: 			continue
119: 		}
120: 		validatedPlugins = append(validatedPlugins, r.bootstrappedPlugin)
121: 	}
122: 	l.log.Debug("Validated", "class", src.PluginClass(ctx), "duration", time.Since(st), "total", len(validatedPlugins))
123: 
124: 	st = time.Now()
125: 	initializedPlugins := []*plugins.Plugin{}
126: 	for _, validatedPlugin := range validatedPlugins {
127: 		initializedPlugin, err := l.initializer.Initialize(ctx, validatedPlugin)
128: 		if err != nil {
129: 			l.recordError(ctx, validatedPlugin, err)
130: 			continue
131: 		}
132: 		initializedPlugins = append(initializedPlugins, initializedPlugin)
133: 	}
134: 	l.log.Debug("Initialized", "class", src.PluginClass(ctx), "duration", time.Since(st))
135: 
136: 	// Clean errors from registry for initialized plugins
137: 	for _, p := range initializedPlugins {
138: 		l.errorTracker.Clear(ctx, p.ID)
139: 	}
140: 
141: 	end(initializedPlugins)
142: 
143: 	return initializedPlugins, nil
144: }
145: 
146: func (l *Loader) Unload(ctx context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
147: 	return l.termination.Terminate(ctx, p)
148: }
149: 
150: func (l *Loader) instrumentLoad(ctx context.Context, src plugins.PluginSource) func([]*plugins.Plugin) {
151: 	start := time.Now()
152: 	sourceLogger := l.log.New("source", src.PluginClass(ctx)).FromContext(ctx)
153: 	sourceLogger.Debug("Loading plugin source...")
154: 
155: 	return func(logger log.Logger, start time.Time) func([]*plugins.Plugin) {
156: 		return func(plugins []*plugins.Plugin) {
157: 			if len(plugins) == 0 {
158: 				logger.Debug("Plugin source loaded, though no plugins were found")
159: 				return
160: 			}
161: 			names := make([]string, len(plugins))
162: 			for i, p := range plugins {
163: 				names[i] = p.ID
164: 			}
165: 			sort.Strings(names)
166: 			pluginsStr := strings.Join(names, ", ")
167: 
168: 			logger.Debug("Plugin source loaded", "plugins", pluginsStr, "duration", time.Since(start))
169: 		}
170: 	}(sourceLogger, start)
171: }
