15: // DefaultConstructor implements the default ConstructFunc used for the Construct step of the Bootstrap stage.
16: //
17: // It uses a pluginFactoryFunc to create plugins and the signatureCalculator to calculate the plugin's signature state.
18: type DefaultConstructor struct {
19: 	pluginFactoryFunc   pluginFactoryFunc
20: 	signatureCalculator plugins.SignatureCalculator
21: 	log                 log.Logger
22: }
23: 
24: // DefaultConstructFunc is the default ConstructFunc used for the Construct step of the Bootstrap stage.
25: func DefaultConstructFunc(cfg *config.PluginManagementCfg, signatureCalculator plugins.SignatureCalculator, assetProvider pluginassets.Provider) ConstructFunc {
26: 	return NewDefaultConstructor(cfg, signatureCalculator, assetProvider).Construct
27: }
28: 
29: // DefaultDecorateFuncs are the default DecorateFuncs used for the Decorate step of the Bootstrap stage.
30: func DefaultDecorateFuncs(cfg *config.PluginManagementCfg) []DecorateFunc {
31: 	return []DecorateFunc{
32: 		AppDefaultNavURLDecorateFunc,
33: 		TemplateDecorateFunc,
34: 		AppChildDecorateFunc(),
35: 		SkipHostEnvVarsDecorateFunc(cfg),
36: 	}
37: }
38: 
39: // NewDefaultConstructor returns a new DefaultConstructor.
40: func NewDefaultConstructor(cfg *config.PluginManagementCfg, signatureCalculator plugins.SignatureCalculator, assetProvider pluginassets.Provider) *DefaultConstructor {
41: 	return &DefaultConstructor{
42: 		pluginFactoryFunc:   NewDefaultPluginFactory(&cfg.Features, assetProvider).createPlugin,
43: 		signatureCalculator: signatureCalculator,
44: 		log:                 log.New("plugins.construct"),
45: 	}
46: }
47: 
48: // Construct will calculate the plugin's signature state and create the plugin using the pluginFactoryFunc.
49: func (c *DefaultConstructor) Construct(ctx context.Context, src plugins.PluginSource, bundle *plugins.FoundBundle) ([]*plugins.Plugin, error) {
50: 	sig, err := c.signatureCalculator.Calculate(ctx, src, bundle.Primary)
51: 	if err != nil {
52: 		c.log.Warn("Could not calculate plugin signature state", "pluginId", bundle.Primary.JSONData.ID, "error", err)
53: 		return nil, err
54: 	}
55: 	plugin, err := c.pluginFactoryFunc(bundle, src.PluginClass(ctx), sig)
56: 	if err != nil {
57: 		c.log.Error("Could not create primary plugin base", "pluginId", bundle.Primary.JSONData.ID, "error", err)
58: 		return nil, err
59: 	}
60: 	res := make([]*plugins.Plugin, 0, len(plugin.Children)+1)
61: 	res = append(res, plugin)
62: 	res = append(res, plugin.Children...)
63: 	return res, nil
64: }
65: 
66: // AppDefaultNavURLDecorateFunc is a DecorateFunc that sets the default nav URL for app plugins.
67: func AppDefaultNavURLDecorateFunc(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
68: 	if p.IsApp() {
69: 		setDefaultNavURL(p)
70: 	}
71: 	return p, nil
72: }
73: 
74: // TemplateDecorateFunc is a DecorateFunc that removes the placeholder for the version and last_update fields.
75: func TemplateDecorateFunc(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
76: 	// %VERSION% and %TODAY% are valid values, according to the plugin schema
77: 	// but it's meant to be replaced by the build system with the actual version and date.
78: 	// If not, it's the same than not having a version or a date.
79: 	if p.Info.Version == "%VERSION%" {
80: 		p.Info.Version = ""
81: 	}
82: 
83: 	if p.Info.Updated == "%TODAY%" {
84: 		p.Info.Updated = ""
85: 	}
86: 
87: 	return p, nil
88: }
89: 
90: func setDefaultNavURL(p *plugins.Plugin) {
91: 	// slugify pages
92: 	for _, include := range p.Includes {
93: 		if include.Slug == "" {
94: 			include.Slug = slugify.Slugify(include.Name)
95: 		}
96: 
97: 		if !include.DefaultNav {
98: 			continue
99: 		}
100: 
101: 		if include.Type == "page" {
102: 			p.DefaultNavURL = path.Join("/plugins/", p.ID, "/page/", include.Slug)
103: 		}
104: 		if include.Type == "dashboard" {
105: 			dboardURL := include.DashboardURLPath()
106: 			if dboardURL == "" {
107: 				p.Logger().Warn("Included dashboard is missing a UID field")
108: 				continue
109: 			}
110: 
111: 			p.DefaultNavURL = dboardURL
112: 		}
113: 	}
114: }
115: 
116: // AppChildDecorateFunc is a DecorateFunc that configures child plugins of app plugins.
117: func AppChildDecorateFunc() DecorateFunc {
118: 	return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
119: 		if p.Parent != nil && p.Parent.IsApp() {
120: 			configureAppChildPlugin(p.Parent, p)
121: 		}
122: 		return p, nil
123: 	}
124: }
125: 
126: func configureAppChildPlugin(parent *plugins.Plugin, child *plugins.Plugin) {
127: 	if !parent.IsApp() {
128: 		return
129: 	}
130: 	child.IncludedInAppID = parent.ID
131: 
132: 	// If the child plugin does not have a version, it will inherit the version from the parent.
133: 	// This is to ensure that the frontend can appropriately cache the plugin assets.
134: 	if child.Info.Version == "" {
135: 		child.Info.Version = parent.Info.Version
136: 	}
137: }
138: 
139: // SkipHostEnvVarsDecorateFunc returns a DecorateFunc that configures the SkipHostEnvVars field of the plugin.
140: // It will be set to true if the FlagPluginsSkipHostEnvVars feature flag is set, and the plugin is not present in the
141: // ForwardHostEnvVars plugin ids list.
142: func SkipHostEnvVarsDecorateFunc(cfg *config.PluginManagementCfg) DecorateFunc {
143: 	return func(_ context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
144: 		p.SkipHostEnvVars = cfg.Features.SkipHostEnvVarsEnabled && !slices.Contains(cfg.ForwardHostEnvVars, p.ID)
145: 		return p, nil
146: 	}
147: }
